class SimilarItemsDrawer {
  constructor() {
    // Lazy initialization - only create when needed
    this.drawer = null;
    this.overlay = null;
    this.isOpen = false;
    this.cache = null; // Lazy initialize cache
    this.abortController = null;
    this.focusHandler = null;
    this.lastTriggerButton = null;
    
    // Bind methods once
    this.handleDocumentClick = this.handleDocumentClick.bind(this);
    this.handleKeydown = this.handleKeydown.bind(this);
    this.handleOverlayClick = this.handleOverlayClick.bind(this);
    
    // Attach minimal event listener
    this.attachInitialListener();
  }

  attachInitialListener() {
    // Use event delegation on document - only one listener
    document.addEventListener("click", this.handleDocumentClick, { passive: false });
  }

  handleDocumentClick(event) {
    const button = event.target.closest(".view-similar-btn");
    
    if (button) {
      event.preventDefault();
      this.lastTriggerButton = button;
      
      // Initialize drawer on first use
      if (!this.drawer) {
        this.initializeDrawer();
      }
      
      this.handleButtonClick(button);
      return;
    }
    
    // Only check close button if drawer exists and is open
    if (this.isOpen && event.target.closest(".similar-items-drawer__close")) {
      this.close();
    }
  }

  initializeDrawer() {
    this.createDrawerElements();
    this.attachDrawerListeners();
  }

  createDrawerElements() {
    // Create overlay
    this.overlay = document.createElement("div");
    this.overlay.className = "similar-items-overlay";
    this.overlay.setAttribute("aria-hidden", "true");
    
    // Create drawer with minimal initial content
    this.drawer = document.createElement("div");
    this.drawer.className = "similar-items-drawer";
    this.drawer.setAttribute("role", "dialog");
    this.drawer.setAttribute("aria-modal", "true");
    this.drawer.setAttribute("aria-labelledby", "similar-items-title");
    
    // Use fragment for better performance
    const fragment = document.createDocumentFragment();
    fragment.appendChild(this.overlay);
    fragment.appendChild(this.drawer);
    document.body.appendChild(fragment);
  }

  attachDrawerListeners() {
    this.overlay.addEventListener("click", this.handleOverlayClick);
    document.addEventListener("keydown", this.handleKeydown);
    
    // Passive: false only when necessary for touch handling
    this.drawer.addEventListener("touchmove", (event) => {
      if (this.isOpen) {
        const content = this.drawer.querySelector(".similar-items-drawer__content");
        if (content && !content.contains(event.target)) {
          event.preventDefault();
        }
      }
    }, { passive: false });
  }

  handleOverlayClick() {
    this.close();
  }

  handleKeydown(event) {
    if (event.key === "Escape" && this.isOpen) {
      this.close();
    }
  }

  async handleButtonClick(button) {
    const productHandle = button.dataset.productHandle;
    
    if (!productHandle) {
      console.error("Product handle not found");
      return;
    }

    // Show loading state and open
    this.showLoader();
    this.open();

    // Lazy initialize cache only when needed
    if (!this.cache) {
      this.cache = new Map();
    }

    // Check cache
    if (this.cache.has(productHandle)) {
      this.renderContent(this.cache.get(productHandle));
      return;
    }

    // Load new content
    await this.loadContent(productHandle);
  }

  showLoader() {
    // Use textContent for security and performance
    this.drawer.innerHTML = `
      <div class="similar-items-drawer__inner">
        <div class="similar-items-drawer__loader">
          <div class="spinner"></div>
          <p>Loading similar items...</p>
        </div>
      </div>
    `;
  }

  async loadContent(productHandle) {
    // Abort any pending requests
    if (this.abortController) {
      this.abortController.abort();
    }
    
    this.abortController = new AbortController();

    try {
      const response = await fetch(`/products/${productHandle}?view=similar-items`, {
        signal: this.abortController.signal,
        headers: {
          "X-Requested-With": "XMLHttpRequest"
        }
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const html = await response.text();
      
      // Store in cache
      this.cache.set(productHandle, html);
      
      // Limit cache size to prevent memory issues
      if (this.cache.size > 10) {
        const firstKey = this.cache.keys().next().value;
        this.cache.delete(firstKey);
      }
      
      this.renderContent(html);
      
    } catch (error) {
      if (error.name === "AbortError") {
        return;
      }
      console.error("Error loading similar items:", error);
      this.renderError();
    } finally {
      this.abortController = null;
    }
  }

  renderContent(html) {
    // Create wrapper if it doesn't exist
    let inner = this.drawer.querySelector(".similar-items-drawer__inner");
    
    if (!inner) {
      inner = document.createElement("div");
      inner.className = "similar-items-drawer__inner";
      this.drawer.appendChild(inner);
    }
    
    inner.innerHTML = html;
    this.initializeDrawerContent();
  }

  renderError() {
    this.drawer.innerHTML = `
      <div class="similar-items-drawer__inner">
        <div class="similar-items-drawer__error">
          <p>Unable to load similar items. Please try again.</p>
          <button type="button" class="similar-items-drawer__close btn">Close</button>
        </div>
      </div>
    `;
  }

  initializeDrawerContent() {
    // Dispatch custom event for other scripts
    document.dispatchEvent(new CustomEvent("similar-items:loaded", {
      detail: { drawer: this.drawer }
    }));
  }

  open() {
    this.isOpen = true;
    document.body.style.overflow = "hidden";
    
    // Use RAF for smooth animation
    requestAnimationFrame(() => {
      this.overlay.classList.add("is-visible");
      this.drawer.classList.add("is-open");
      this.overlay.setAttribute("aria-hidden", "false");
    });
    
    this.trapFocus();
  }

  close() {
    if (!this.isOpen) return;
    
    this.isOpen = false;
    document.body.style.overflow = "";
    this.overlay.classList.remove("is-visible");
    this.drawer.classList.remove("is-open");
    this.overlay.setAttribute("aria-hidden", "true");
    
    this.returnFocus();
  }

  trapFocus() {
    const focusableElements = this.drawer.querySelectorAll(
      'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
    );
    
    if (focusableElements.length === 0) return;

    const firstElement = focusableElements[0];
    const lastElement = focusableElements[focusableElements.length - 1];

    // Focus first element after render
    requestAnimationFrame(() => {
      firstElement?.focus();
    });

    // Reuse handler to avoid creating new functions
    if (!this.focusHandler) {
      this.focusHandler = (event) => {
        if (event.key === "Tab") {
          const focusable = this.drawer.querySelectorAll(
            'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
          );
          
          if (focusable.length === 0) return;
          
          const first = focusable[0];
          const last = focusable[focusable.length - 1];
          
          if (event.shiftKey && document.activeElement === first) {
            last.focus();
            event.preventDefault();
          } else if (!event.shiftKey && document.activeElement === last) {
            first.focus();
            event.preventDefault();
          }
        }
      };
    }

    this.drawer.addEventListener("keydown", this.focusHandler);
  }

  returnFocus() {
    if (this.focusHandler) {
      this.drawer.removeEventListener("keydown", this.focusHandler);
    }
    
    // Return focus to the button that opened the drawer
    if (this.lastTriggerButton) {
      this.lastTriggerButton.focus();
    }
  }

  clearCache() {
    if (this.cache) {
      this.cache.clear();
    }
  }

  destroy() {
    // Cleanup method for SPA or dynamic page updates
    document.removeEventListener("click", this.handleDocumentClick);
    document.removeEventListener("keydown", this.handleKeydown);
    
    if (this.overlay) {
      this.overlay.removeEventListener("click", this.handleOverlayClick);
      this.overlay.remove();
    }
    
    if (this.drawer) {
      this.drawer.remove();
    }
    
    if (this.abortController) {
      this.abortController.abort();
    }
    
    this.clearCache();
  }
}

// Lazy initialization - only create instance when DOM is ready
let similarItemsDrawerInstance = null;

function initSimilarItemsDrawer() {
  if (!similarItemsDrawerInstance) {
    similarItemsDrawerInstance = new SimilarItemsDrawer();
    window.similarItemsDrawer = similarItemsDrawerInstance;
  }
  return similarItemsDrawerInstance;
}

// Use passive event listener for better scroll performance
if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", initSimilarItemsDrawer, { once: true });
} else {
  initSimilarItemsDrawer();
}
